SELECT year, lexical_index, index_source, index_methodology
FROM lexical_index
WHERE country_id = 1 AND year = 1789;

SELECT year, country_id, voter_turnout, freedom_of_press
FROM democratization_indicators
WHERE country_id = 1 AND year = 1789;

SELECT MAX(freedom_of_press) AS max_freedom_of_press
FROM democratization_indicators
WHERE year = 1789;

SELECT gdp_growth_rate
FROM gdp
WHERE year = 1789 AND country_id = 0;

SELECT COUNT(*) AS coup_count
FROM democratic_breakdowns
WHERE breakdown_type = 'coup';

SELECT breakdown_type
FROM democratic_breakdowns
WHERE year = 1929;

SELECT country_name
FROM countries
WHERE country_id = 0;

SELECT AVG(gdp_per_capita) AS avg_gdp_per_capita
FROM gdp
WHERE year = 1790;
